          method: 'POST',
          credentials: 'include',
          headers: { 'Content-Type': 'application/x-www-form-urlencoded' },
          body: fd.toString()
        });
        results.getChatMsgListExtra1 = { status: r.status, text: (await r.text()).substring(0, 500) };
      } catch(e) {
        results.getChatMsgListExtra1 = { err: e.message };
